import { generateText } from 'ai';
import { vexMiddleware } from '@vex_dev/sdk';

const vex = vexMiddleware({
  projectId: 'legal-vex-project',
  rules: [
    'block_pii',
    'validate_legal_citations',
    'require_attorney_review_disclaimer'
  ]
});

export async function legalResearch(prompt: string) {
  const { text } = await generateText({
    model: 'gpt-4o',
    prompt,
    ...vex.middleware()
  });
  return text;
}

import { streamText } from 'ai';
import { vexMiddleware } from '@vex_dev/sdk';

const vex = vexMiddleware({
  projectId: 'legal-vex-project',
  streamRules: ['no_partial_hallucinations', 'legal_content_filter']
});

export async function streamLegalAdvice(prompt: string) {
  const result = await streamText({
    model: 'claude-3-5-sonnet',
    prompt,
    ...vex.streamMiddleware()
  });

  return result;
}

